import { Effect } from "effect"

export const preview = Effect.gen(function*() {
  yield* Effect.services<unknown>()
  return yield* Effect.fail<any>("boom")
})

import * as Effect from "effect/Effect"

interface ServiceShape { value: number }

export class InvalidContextTag
  extends Effect.Tag("ValidContextTag")<ValidContextTag, ServiceShape>() {}

declare class ValidContextTag {}

import * as Effect from "effect/Effect"

// This preview only reports when the workspace resolves duplicated
// Effect package versions.
export const preview = Effect.succeed(true)

import { Effect } from "effect"

export class Preview<_A> extends Effect.Service<Preview<any>>()("Preview", {
  succeed: {}
}) {}

import { Effect, ServiceMap } from "effect"

class Db extends ServiceMap.Service<Db>()("Db", { make: Effect.succeed({}) }) {}

// @ts-expect-error
export const preview: Effect.Effect<void> = Db.asEffect().pipe(Effect.asVoid)

import type * as Effect from "effect/Effect"
import { Data } from "effect"

class Boom extends Data.TaggedError("Boom")<{}> {}
declare const effect: Effect.Effect<number, Boom>

// @ts-expect-error
export const preview: () => Effect.Effect<number> = () => effect

import { Effect, Layer, ServiceMap } from "effect"

class A extends ServiceMap.Service<A>()("A", { make: Effect.succeed({}) }) {
  static Default = Layer.effect(this, this.make)
}
declare const layer: Layer.Layer<A, never, A>
// @ts-expect-error
export const preview: Layer.Layer<A> = layer

import * as Effect from "effect/Effect"

export const preview = Effect.gen(function*() {
  yield* Effect.log("before")
  yield* Effect.fail("boom")
})

import * as Effect from "effect/Effect"

export const preview = Effect.gen(function*() {
  const value = yield Effect.succeed(1)
  return value
})

import * as Effect from "effect/Effect"

export class BadService extends Effect.Service<BadService>()("BadService", {
  // @ts-expect-error
  succeed: "hello" as const
}) {}

import { Effect } from "effect"

export const preview = Effect.gen(function*() {
  // @ts-expect-error
  return yield* Effect.runtime()
})

import * as Effect from "effect/Effect"

// @effect-codegens accessors:stale-preview
export class Preview extends Effect.Service<Preview>()("Preview", {
  accessors: true,
  effect: Effect.succeed({ value: Effect.succeed(1) })
}) {}

import * as Schema from "effect/Schema"

export class User extends Schema.Class<User>("User")({ name: Schema.String }) {
  constructor(readonly input: { name: string }) { super(input) }
}

import * as Effect from "effect/Effect"

export class Preview extends Effect.Service<Preview>()("Preview", {
  accessors: true,
  effect: Effect.succeed({ get: <A>(value: A) => Effect.succeed(value) })
}) {}

import { Effect } from "effect"

export const preview = Effect.succeed(1).pipe(
  Effect.catch(() => Effect.succeed(0))
)

import * as Effect from "effect/Effect"

export const preview = Effect.fn("preview")(function*() {
  return yield* Effect.succeed(1)
})()

import * as Effect from "effect/Effect"

export const preview = Effect.gen(function*(_) {
  return yield* Effect.succeed(1)
})

import { Effect } from "effect"

export const preview = Effect.try({
  try: () => JSON.parse("{"),
  catch: (error) => Effect.logError(error)
})

import * as Effect from "effect/Effect"

export const preview: Effect.Effect<void> = Effect.succeed(
  Effect.log("nested")
)

import { Effect } from "effect"

export const preview = Effect.tryPromise({
  try: async () => 1,
  catch: (error) => new Error(String(error))
})

import { Effect, Layer, ServiceMap } from "effect"

class A extends ServiceMap.Service<A>()("A", { make: Effect.succeed({}) }) {
  static Default = Layer.effect(this, this.make)
}
class B extends ServiceMap.Service<B>()("B", { make: Effect.as(A.asEffect(), {}) }) {
  static Default = Layer.effect(this, this.make)
}
export const preview = Layer.mergeAll(A.Default, B.Default)

import type { Effect } from "effect"
import { ServiceMap } from "effect"

class FileSystem extends ServiceMap.Service<FileSystem, {
  write: (s: string) => Effect.Effect<void>
}>()("FileSystem") {}

export class Cache extends ServiceMap.Service<Cache, {
  read: Effect.Effect<string, never, FileSystem>
  save: () => Effect.Effect<void, never, FileSystem>
}>()("Cache") {}

import { Effect, Layer, ServiceMap } from "effect"

class A extends ServiceMap.Service<A>()("A", { make: Effect.succeed({}) }) {
  static Default = Layer.effect(this, this.make)
}
class B extends ServiceMap.Service<B>()("B", { make: Effect.succeed({}) }) {
  static Default = Layer.effect(this, this.make)
}
export const preview = Effect.void.pipe(Effect.provide(A.Default), Effect.provide(B.Default))

import * as Effect from "effect/Effect"

export const preview = Effect.gen(function*() {
  return Effect.succeed(1)
})

import { Effect } from "effect"

export const preview = Effect.gen(function*() {
  const run = () => Effect.runSync(Effect.succeed(1))
  return run()
})

import * as Effect from "effect/Effect"
import * as Schema from "effect/Schema"

const Person = Schema.Struct({ name: Schema.String, age: Schema.Number })

export const preview = Effect.gen(function*() {
  const input = yield* Effect.succeed({ name: "Ada", age: 1 })
  return Schema.decodeSync(Person)(input)
})

import * as Context from "effect/Context"
import * as Effect from "effect/Effect"
import * as Layer from "effect/Layer"

class Cache extends Context.Tag("Cache")<Cache, { ok: true }>() {}
export const preview = Layer.effect(Cache, Effect.gen(function*() {
  yield* Effect.addFinalizer(() => Effect.void)
  return { ok: true as const }
}))

import { Effect, Layer, ServiceMap } from "effect"

class Config extends ServiceMap.Service<Config>()("Config", { make: Effect.succeed({}) }) {
  static Default = Layer.effect(this, this.make)
}
export const preview = Effect.void.pipe(Effect.provide(Config.Default))

import * as Effect from "effect/Effect"

export const preview = Effect.gen(function*() {
  try { return yield* Effect.succeed(1) }
  catch { return 0 }
})

import { Effect } from "effect"

export const preview = Effect.tryPromise({
  try: async () => 1,
  catch: (error) => error
})

import { Effect } from "effect"

export const preview = Effect.gen(function*() {
  const text = yield* Effect.succeed('{"ok":true}')
  return JSON.parse(text)
})

import { Effect } from "effect"

class WrappedError {
  constructor(readonly cause: unknown) {}
}

export const preview = Effect.fail("boom").pipe(
  Effect.catch((cause) => Effect.fail(new WrappedError(cause)))
)

import { ServiceMap } from "effect"

export class RenamedService
  extends ServiceMap.Service<RenamedService, {}>()("CustomIdentifier") {}

import * as Effect from "effect/Effect"

export const preview = () => Effect.gen(function*() {
  return yield* Effect.succeed(1)
})

import { Effect } from "effect"

export const preview = Effect.succeed(1).pipe(
  Effect.map(() => undefined)
)

import { identity, Schema } from "effect"

const User = Schema.Struct({ id: Schema.Number })
export const preview = identity(identity(Schema.decodeEffect(User)({ id: 1 })))

import * as Effect from "effect/Effect"

class Db extends Effect.Service<Db>()("Db", { succeed: { ok: true } }) {}
export class Repo extends Effect.Service<Repo>()("Repo", {
  effect: Effect.gen(function*() {
    yield* Db
    return { all: Effect.succeed([] as Array<number>) }
  })
}) {}

import * as Schema from "effect/Schema"

export class Preview
  extends Schema.TaggedClass<Preview>("Preview")("Preview", {
    value: Schema.String
  }) {}

import * as Schema from "effect/Schema"

export const preview = Schema.Struct({
  _tag: Schema.Literal("User"),
  name: Schema.String
})

import * as Effect from "effect/Effect"

export const preview = Effect.gen(function*() {
  return yield* Effect.succeed(1)
})

import * as Data from "effect/Data"
import * as Effect from "effect/Effect"

class Boom extends Data.TaggedError("Boom")<{}> {}
export const preview = Effect.gen(function*() {
  yield* Effect.fail(new Boom())
})
